const seed = (slug, title, category, difficulty, tags, focus, core, example, boundary) => ({
  slug,
  title,
  category,
  difficulty,
  tags,
  focus,
  core,
  example,
  boundary,
});

const cleanFragment = (value) => String(value || "")
  .trim()
  .replace(/[。！？；]+$/u, "");

const stableVariant = (slug) => [...slug]
  .reduce((total, character) => total + character.codePointAt(0), 0);

const guidePatterns = [
  ({ focus, boundary }) => `回答“${focus}”时，先给出核心结论，再补一个能检查结论的例子，最后主动说明这条边界：${boundary}。`,
  ({ focus, boundary }) => `组织答案时围绕“${focus}”展开：把定义或机制讲清楚，用具体例子验证，并说明${boundary}。`,
  ({ focus, boundary }) => `这题不要只报术语。先解释“${focus}”的核心逻辑，再说明如何验证，最后指出${boundary}。`,
  ({ focus, boundary }) => `建议按“结论—例子—边界”回答“${focus}”：核心判断要明确，验证要可复现，并说明${boundary}。`,
  ({ focus, boundary }) => `先用自己的话说清“${focus}”，再给出一项可检查的证据或例子；结尾别漏掉${boundary}。`,
  ({ focus, boundary }) => `口述“${focus}”时，先回答它是什么或怎么做，再用例子落地，最后交代适用限制：${boundary}。`,
];

const answerPatterns = [
  ({ core, example, boundary }) => `${core}。例如，${example}。需要注意的是，${boundary}。`,
  ({ core, example, boundary }) => `关键点是，${core}。验证时可以这样做：${example}。但${boundary}。`,
  ({ core, example, boundary }) => `${core}。一个直接的检查办法是：${example}。这个结论的边界是，${boundary}。`,
  ({ core, example, boundary }) => `这件事可以概括为：${core}。落到实验或实现上，${example}。同时要确认，${boundary}。`,
  ({ core, example, boundary }) => `${core}。要验证这一点，可以采用这个办法：${example}。使用时不能忽略，${boundary}。`,
  ({ core, example, boundary }) => `核心判断是，${core}。实际验证可采用这个办法：${example}。此外，${boundary}。`,
  ({ core, example, boundary }) => `${core}。具体例子是，${example}。真正落地前还要检查，${boundary}。`,
  ({ core, example, boundary }) => `可以从这条主线理解：${core}。再用一个最小验证说明：${example}。最后明确限制：${boundary}。`,
];

const followupPatterns = [
  ({ focus, core, example, boundary }) => [
    [`请把“${focus}”的核心结论压缩成一句话。`, core],
    [`你会用什么例子或检查验证“${focus}”？`, example],
    [`“${focus}”最重要的适用边界是什么？`, boundary],
  ],
  ({ focus, core, example, boundary }) => [
    [`不铺背景，直接说明“${focus}”的核心机制或判断。`, core],
    [`把“${focus}”落到一个可检查的例子，你会怎么做？`, example],
    [`什么情况下不能直接套用“${focus}”？`, boundary],
  ],
  ({ focus, core, example, boundary }) => [
    [`面试官要求一句话概括“${focus}”时，你怎么说？`, core],
    [`你会怎样用数据、代码或手算验证“${focus}”？`, example],
    [`回答“${focus}”时必须主动补充哪项限制？`, boundary],
  ],
  ({ focus, core, example, boundary }) => [
    [`“${focus}”最需要讲清的核心内容是什么？`, core],
    [`哪项具体检查可以支撑你对“${focus}”的判断？`, example],
    [`“${focus}”最容易被忽略的前提是什么？`, boundary],
  ],
  ({ focus, core, example, boundary }) => [
    [`如果只保留一个要点，“${focus}”是什么？`, core],
    [`给出一个可以复现或手工检查“${focus}”的办法。`, example],
    [`在哪种条件下，“${focus}”会失效或被误读？`, boundary],
  ],
  ({ focus, core, example, boundary }) => [
    [`请用自己的话说明“${focus}”的核心做法。`, core],
    [`你准备怎样举例证明自己理解“${focus}”？`, example],
    [`使用“${focus}”前还要确认什么？`, boundary],
  ],
];

const behaviorFollowups = ({ focus, core, example, boundary }) => [
  [`回答“${focus}”时应覆盖哪些本人事实？`, core],
  [`可以用什么真实证据支撑“${focus}”？`, example],
  [`复盘“${focus}”时必须主动承认哪项边界？`, boundary],
];

const interviewerQuestionFollowups = ({ core, example, boundary }) => [
  ["你希望通过反向提问判断什么？", core],
  ["怎样针对这一个岗位准备问题？", example],
  ["哪些反向提问方式应该避免？", boundary],
];

const makeQuestion = (item) => {
  const normalized = {
    focus: cleanFragment(item.focus),
    core: cleanFragment(item.core),
    example: cleanFragment(item.example),
    boundary: cleanFragment(item.boundary),
  };
  const variant = stableVariant(item.slug);
  const isBehaviorQuestion = item.category === "项目与行为面";
  const isInterviewerQuestion = item.slug === "career-questions-for-interviewer";
  const guide = isInterviewerQuestion
    ? `回答“${normalized.focus}”时，先说选问题的标准，再给两到四个针对当前岗位的问题，最后说明${normalized.boundary}。`
    : (isBehaviorQuestion
      ? `这类题不要套用别人的经历。围绕“${normalized.focus}”讲清背景、目标、本人动作与真实证据，最后说明${normalized.boundary}。`
      : guidePatterns[variant % guidePatterns.length](normalized));
  const answer = isInterviewerQuestion
    ? `${normalized.core}。准备时可以${normalized.example}。同时，${normalized.boundary}。`
    : (isBehaviorQuestion
      ? `${normalized.core}。证据部分只写本人真实材料：${normalized.example}。还要明确，${normalized.boundary}。`
      : answerPatterns[Math.floor(variant / guidePatterns.length) % answerPatterns.length](normalized));
  const followups = (isInterviewerQuestion
    ? interviewerQuestionFollowups(normalized)
    : (isBehaviorQuestion
      ? behaviorFollowups(normalized)
      : followupPatterns[variant % followupPatterns.length](normalized)))
    .map(([q, a]) => ({ q, a }));
  return {
    slug: item.slug,
    title: item.title,
    category: item.category,
    difficulty: item.difficulty,
    tags: item.tags,
    guide,
    answer,
    followups,
  };
};

